 8→export function PageTransition({ children }: PageTransitionProps) {
 9→  return (
10→    <motion.div
11→      initial={{ opacity: 0, y: 20 }}
12→      animate={{ opacity: 1, y: 0 }}
13→      exit={{ opacity: 0, y: -20 }}
14→      transition={{ duration: 0.3, ease: "easeInOut" }}
15→    >
16→      {children}
17→    </motion.div>
18→  );
19→}
