 1→@use "variables" as *;
 2→
 3→// Media queries
 4→@mixin mobile {
 5→  @media (max-width: $bpMobile) {
 6→    @content;
 7→  }
 8→}
 9→
10→@mixin tablet {
11→  @media (max-width: $bpTablet) {
12→    @content;
13→  }
14→}
15→
16→@mixin tabletUp {
17→  @media (min-width: ($bpTablet + 1)) {
18→    @content;
19→  }
20→}
21→
22→@mixin desktop {
23→  @media (min-width: $bpDesktop) {
24→    @content;
25→  }
26→}
27→
28→@mixin wide {
29→  @media (min-width: $bpWide) {
30→    @content;
31→  }
32→}
33→
34→// Glass morphism
35→@mixin glass {
36→  background: $glassBg;
37→  backdrop-filter: blur($glassBlur);
38→  -webkit-backdrop-filter: blur($glassBlur);
39→  border: 1px solid $glassBorder;
40→}
41→
42→@mixin glassHover {
43→  background: $glassBgHover;
44→  border-color: $glassBorderHover;
45→}
46→
47→// Container
48→@mixin container {
49→  width: 100%;
50→  max-width: $maxWidth;
51→  margin: 0 auto;
52→  padding: 0 $space6;
53→
54→  @include tablet {
55→    padding: 0 $space4;
56→  }
57→}
58→
59→// Truncate
60→@mixin truncate($lines: 1) {
61→  @if $lines == 1 {
62→    overflow: hidden;
63→    text-overflow: ellipsis;
64→    white-space: nowrap;
65→  } @else {
66→    display: -webkit-box;
67→    -webkit-line-clamp: $lines;
