import { useNavigate } from "react-router-dom";
import { motion } from "motion/react";
import { PageTransition } from "@/components/PageTransition/PageTransition";
import { SearchBar } from "@/components/SearchBar/SearchBar";
import { CandidateCard } from "@/components/CandidateCard/CandidateCard";
import { useSearch } from "@/hooks/useSearch";
import styles from "./Search.module.scss";

const containerVariants = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.06 } },
};

const cardVariants = {
  hidden: { opacity: 0, y: 20, scale: 0.95 },
  visible: {
    opacity: 1,
    y: 0,
    scale: 1,
    transition: { duration: 0.4, ease: "easeOut" as const },
  },
};

export function Search() {
  const navigate = useNavigate();
  const { query, setQuery, results, loading, error } = useSearch();

  return (
    <PageTransition>
      <div className={styles.search}>
        <div className={styles.header}>
          <motion.h1
            className={styles.title}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5 }}
          >
            {query ? "Search Results" : "Discover Talent"}
          </motion.h1>
          <motion.p
            className={styles.subtitle}
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.5, delay: 0.1 }}
          >
            {query
              ? `${results.length} candidate${results.length !== 1 ? "s" : ""} found`
              : "Use AI-powered search to find your perfect candidates"}
          </motion.p>
        </div>

        <div className={styles.searchWrapper}>
          <SearchBar value={query} onChange={setQuery} loading={loading} />
        </div>

        {error && (
          <div className={styles.error}>
            <p>Something went wrong: {error}</p>
          </div>
        )}

        {loading && results.length === 0 ? (
          <div className={styles.grid}>
            {Array.from({ length: 6 }).map((_, i) => (
              <div key={i} className={styles.skeleton}>
                <div className={styles.skeletonThumb} />
                <div className={styles.skeletonContent}>
                  <div className={styles.skeletonLine} style={{ width: "60%" }} />
                  <div className={styles.skeletonLine} style={{ width: "40%" }} />
                  <div className={styles.skeletonLine} style={{ width: "80%" }} />
                </div>
              </div>
            ))}
          </div>
        ) : results.length > 0 ? (
          <motion.div
            className={styles.grid}
            variants={containerVariants}
            initial="hidden"
            animate="visible"
            key={query}
          >
            {results.map((result) => (
              <motion.div key={result.candidateId} variants={cardVariants}>
                <CandidateCard
                  candidate={result.candidate}
                  score={result.score}
                  matchReason={result.matchReason}
                  onClick={() => navigate(`/candidate/${result.candidateId}`)}
                />
              </motion.div>
            ))}
          </motion.div>
        ) : (
          !loading && (
            <motion.div
              className={styles.empty}
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
            >
              <svg
                width="64"
                height="64"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="1.5"
              >
                <circle cx="11" cy="11" r="8" />
                <path d="m21 21-4.35-4.35" />
              </svg>
              <h3>No candidates found</h3>
              <p>Try adjusting your search query</p>
            </motion.div>
          )
        )}
      </div>
    </PageTransition>
  );
}

import { useParams, useNavigate } from "react-router-dom";
import { motion } from "motion/react";
import type { Candidate } from "@rearden/types";
import { PageTransition } from "@/components/PageTransition/PageTransition";
import { VideoPlayer } from "@/components/VideoPlayer/VideoPlayer";
import { SkillTag } from "@/components/SkillTag/SkillTag";
import { Button } from "@/components/Button/Button";
import { useApi } from "@/hooks/useApi";
import styles from "./CandidateProfile.module.scss";

const availabilityLabels: Record<string, string> = {
  immediate: "Available immediately",
  "2weeks": "Available in 2 weeks",
  "1month": "Available in 1 month",
  "3months": "Available in 3 months",
};

export function CandidateProfile() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { data: candidate, loading, error } = useApi<Candidate>(`/candidates/${id}`);

  if (loading) {
    return (
      <PageTransition>
        <div className={styles.loading}>
          <div className={styles.spinner} />
          <p>Loading profile...</p>
        </div>
      </PageTransition>
    );
  }

  if (error || !candidate) {
    return (
      <PageTransition>
        <div className={styles.error}>
          <h2>Candidate not found</h2>
          <p>The candidate you're looking for doesn't exist.</p>
          <Button variant="secondary" onClick={() => navigate("/search")}>
            Back to Search
          </Button>
        </div>
      </PageTransition>
    );
  }

  return (
    <PageTransition>
      <div className={styles.profile}>
        <motion.div
          className={styles.videoSection}
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
        >
          {candidate.videoUrl ? (
            <VideoPlayer
              src={candidate.videoUrl}
              poster={candidate.thumbnailUrl ?? undefined}
            />
          ) : (
            <div className={styles.noVideo}>
              <svg
                width="48"
                height="48"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="1.5"
              >
                <path d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" />
              </svg>
              <p>No video available</p>
            </div>
          )}
        </motion.div>

        <motion.div
          className={styles.info}
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.15 }}
        >
          <div className={styles.nameSection}>
            <h1 className={styles.name}>{candidate.name}</h1>
            <p className={styles.title}>{candidate.title}</p>
          </div>

          <div className={styles.meta}>
            <div className={styles.metaItem}>
              <svg
                width="16"
                height="16"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
              >
                <path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z" />
                <circle cx="12" cy="10" r="3" />
              </svg>
              {candidate.location}
            </div>
            <div className={styles.metaItem}>
              <svg
                width="16"
                height="16"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
              >
                <rect x="2" y="7" width="20" height="14" rx="2" ry="2" />
                <path d="M16 21V5a2 2 0 00-2-2h-4a2 2 0 00-2 2v16" />
              </svg>
              {candidate.experience} year{candidate.experience !== 1 ? "s" : ""} experience
            </div>
            <div className={styles.metaItem}>
              <svg
                width="16"
                height="16"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
              >
                <circle cx="12" cy="12" r="10" />
                <polyline points="12 6 12 12 16 14" />
              </svg>
              {availabilityLabels[candidate.availability] ?? candidate.availability}
            </div>
          </div>

          <div className={styles.section}>
            <h2 className={styles.sectionTitle}>About</h2>
            <p className={styles.bio}>{candidate.bio}</p>
          </div>

          <div className={styles.section}>
            <h2 className={styles.sectionTitle}>Skills</h2>
            <div className={styles.skills}>
              {candidate.skills.map((skill) => (
                <SkillTag key={skill} skill={skill} size="md" />
              ))}
            </div>
          </div>

          <div className={styles.actions}>
            <Button variant="primary" size="lg">
              Contact Candidate
            </Button>
            <Button
              variant="ghost"
              size="lg"
              onClick={() => navigate("/search")}
            >
              Back to Search
            </Button>
          </div>
        </motion.div>
      </div>
    </PageTransition>
  );
}

