@use "../../styles/variables" as *;
@use "../../styles/mixins" as *;

.profile {
  @include container;
  padding-top: $space10;
  padding-bottom: $space10;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: $space10;
  align-items: start;

  @include tablet {
    grid-template-columns: 1fr;
    gap: $space6;
  }
}

.videoSection {
  position: sticky;
  top: calc($navbarHeight + $space6);

  @include tablet {
    position: static;
  }
}

.noVideo {
  aspect-ratio: 16 / 9;
  @include glass;
  border-radius: $radiusLg;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: $space3;
  color: $textMuted;
}

.info {
  display: flex;
  flex-direction: column;
  gap: $space6;
}

.nameSection {
  display: flex;
  flex-direction: column;
  gap: $space1;
}

.name {
  font-size: $fontSize32;
  font-weight: 700;

  @include tablet {
    font-size: $fontSize24;
  }
}

.title {
  font-size: $fontSize18;
  color: $textSecondary;
}

.meta {
  display: flex;
  flex-wrap: wrap;
  gap: $space4;
}

.metaItem {
  display: flex;
  align-items: center;
  gap: $space2;
  font-size: $fontSize14;
  color: $textSecondary;

  svg {
    color: $accentPurple;
    flex-shrink: 0;
  }
}

.section {
  display: flex;
  flex-direction: column;
  gap: $space3;
}

.sectionTitle {
  font-size: $fontSize16;
  font-weight: 600;
  color: $textSecondary;
  text-transform: uppercase;
  letter-spacing: 1px;
  font-size: $fontSize12;
}

.bio {
  font-size: $fontSize16;
  line-height: 1.7;
  color: $textSecondary;
}

.skills {
  display: flex;
  flex-wrap: wrap;
  gap: $space2;
}

.actions {
  display: flex;
  gap: $space3;
  padding-top: $space4;

  @include mobile {
    flex-direction: column;
  }
}

.loading {
  @include container;
  padding-top: $space20;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: $space4;
  color: $textSecondary;
}

.spinner {
  width: 32px;
  height: 32px;
  border: 3px solid $bgSurface;
  border-top-color: $accentPurple;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

.error {
  @include container;
  padding-top: $space20;
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: $space4;

  h2 {
    font-size: $fontSize24;
  }

  p {
    color: $textSecondary;
  }
}

