import {
  createContext,
  useContext,
  useEffect,
  useState,
  type ReactNode,
} from "react";

type Theme =
  | "y2k"
  | "purple-night"
  | "rearden-metal"
  | "steel-frost"
  | "forge"
  | "neon"
  | "daylight"
  | "bliss"
  | "aurora"
  | "meadow";

interface ThemeContextValue {
  theme: Theme;
  setTheme: (theme: Theme) => void;
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

const STORAGE_KEY = "rearden-theme";

const THEMES: { value: Theme; label: string }[] = [
  { value: "y2k", label: "Y2K" },
  { value: "purple-night", label: "Purple Night" },
  { value: "rearden-metal", label: "Rearden Metal" },
  { value: "steel-frost", label: "Steel Frost" },
  { value: "forge", label: "Forge" },
  { value: "neon", label: "Neon Y2K" },
  { value: "daylight", label: "Daylight" },
  { value: "bliss", label: "Bliss" },
  { value: "aurora", label: "Aurora" },
  { value: "meadow", label: "Meadow" },
];

const THEME_VALUES = new Set<string>(THEMES.map((t) => t.value));

function getInitialTheme(): Theme {
  const stored = localStorage.getItem(STORAGE_KEY);
  if (stored && THEME_VALUES.has(stored)) return stored as Theme;
  return "y2k";
}

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [theme, setTheme] = useState<Theme>(getInitialTheme);

  useEffect(() => {
    document.documentElement.setAttribute("data-theme", theme);
    localStorage.setItem(STORAGE_KEY, theme);
  }, [theme]);

  return (
    <ThemeContext.Provider value={{ theme, setTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error("useTheme must be used within ThemeProvider");
  return ctx;
}

export { THEMES };
export type { Theme };

