@use "../../styles/variables" as *;
@use "../../styles/mixins" as *;

.navbar {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  height: $navbarHeight;
  @include glass;
  z-index: 100;
}

.container {
  @include container;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.logoLink {
  display: flex;
  align-items: center;
  transition: opacity $transitionFast;

  &:hover {
    opacity: 0.8;
  }
}

.links {
  display: flex;
  align-items: center;
  gap: $space8;
}

.link {
  position: relative;
  display: flex;
  align-items: center;
  height: $navbarHeight;
  font-size: $fontSize14;
  font-weight: 500;
  color: $textSecondary;
  transition: color $transitionBase;

  &:hover {
    color: $textPrimary;
  }
}

.indicator {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 2px;
  background: linear-gradient(90deg, $accentPurple 0%, $accentTeal 100%);
  border-radius: $radiusFull;
}

.soundToggle {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  border-radius: $radiusMd;
  color: $textSecondary;
  transition: all $transitionFast;

  &:hover {
    color: $textPrimary;
    background: $glassBgHover;
  }
}

.themeSelect {
  margin-left: $space1;
}

