import type { Conversation } from "@/data/mockConversations";
import styles from "./ConversationList.module.scss";

interface ConversationListProps {
  conversations: Conversation[];
  onSelect: (id: string) => void;
}

function timeAgo(date: Date): string {
  const seconds = Math.floor((Date.now() - date.getTime()) / 1000);
  if (seconds < 60) return "now";
  const minutes = Math.floor(seconds / 60);
  if (minutes < 60) return `${minutes}m`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours}h`;
  return `${Math.floor(hours / 24)}d`;
}

export function ConversationList({ conversations, onSelect }: ConversationListProps) {
  return (
    <div className={styles.list}>
      {conversations.map((conv) => {
        const lastMsg = conv.messages[conv.messages.length - 1];
        return (
          <button
            key={conv.id}
            className={styles.item}
            onClick={() => onSelect(conv.id)}
          >
            <div className={styles.avatar}>{conv.candidateInitial}</div>
            <div className={styles.content}>
              <div className={styles.header}>
                <span className={styles.name}>{conv.candidateName}</span>
                {lastMsg && (
                  <span className={styles.time}>{timeAgo(lastMsg.timestamp)}</span>
                )}
              </div>
              {lastMsg && (
                <p className={styles.preview}>{lastMsg.text}</p>
              )}
            </div>
            {conv.unread > 0 && (
              <span className={styles.unreadBadge}>{conv.unread}</span>
            )}
          </button>
        );
      })}
    </div>
  );
}

