### 8. KEY SCSS MIXINS (_mixins.scss)

```scss
// Media queries
@mixin mobile { @media (max-width: $bpMobile) { @content; } }
@mixin tablet { @media (max-width: $bpTablet) { @content; } }
@mixin tabletUp { @media (min-width: ($bpTablet + 1)) { @content; } }
@mixin desktop { @media (min-width: $bpDesktop) { @content; } }
@mixin wide { @media (min-width: $bpWide) { @content; } }

// Glass morphism
@mixin glass {
  background: $glassBg;
  backdrop-filter: blur($glassBlur);
  -webkit-backdrop-filter: blur($glassBlur);
  border: 1px solid $glassBorder;
}

// Text truncation
@mixin truncate($lines: 1) {
  @if $lines == 1 {
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  } @else {
    display: -webkit-box;
    -webkit-line-clamp: $lines;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }
}

// Custom scrollbar
@mixin customScrollbar {
  &::-webkit-scrollbar { width: 6px; }
  &::-webkit-scrollbar-thumb {
    background: $textMuted;
    border-radius: $radiusFull;
  }
}

// Container max-width wrapper
@mixin container {
  width: 100%;
  max-width: $maxWidth;  // 1200px
  margin: 0 auto;
  padding: 0 $space6;  // 24px sides
  @include tablet { padding: 0 $space4; }  // 16px on tablet
}
```

