 1→import { Hono } from "hono";
 2→import type { ApiResponse, Candidate } from "@rearden/types";
 3→import { mockCandidates } from "../data/mockCandidates.js";
 4→
 5→export const candidateRoutes = new Hono();
 6→
 7→// In-memory storage (starts with mock data)
 8→let candidates: Candidate[] = [...mockCandidates];
 9→
10→// GET /api/candidates - Get all candidates
11→candidateRoutes.get("/", (c) => {
12→  return c.json<ApiResponse<Candidate[]>>({
13→    success: true,
14→    data: candidates,
15→  });
16→});
17→
18→// GET /api/candidates/:id - Get candidate by ID
19→candidateRoutes.get("/:id", (c) => {
20→  const id = c.req.param("id");
21→  const candidate = candidates.find((cand) => cand.id === id);
22→
23→  if (!candidate) {
24→    return c.json<ApiResponse>(
25→      {
26→        success: false,
27→        error: "Candidate not found",
28→      },
29→      404
30→    );
31→  }
32→
33→  return c.json<ApiResponse<Candidate>>({
34→    success: true,
35→    data: candidate,
36→  });
37→});
38→
39→// POST /api/candidates - Create new candidate
40→candidateRoutes.post("/", async (c) => {
41→  try {
42→    const body = await c.req.json();
43→
44→    // Generate new candidate with ID and timestamps
45→    const now = new Date().toISOString();
46→    const newCandidate: Candidate = {
47→      id: crypto.randomUUID(),
48→      createdAt: now,
49→      updatedAt: now,
50→      role: "candidate" as const,
51→      resume: null,
52→      skills: [],
53→      experience: 0,
54→      videoUrl: null,
55→      thumbnailUrl: null,
56→      location: "",
57→      title: "",
58→      bio: "",
59→      availability: "immediate",
60→      ...body,
61→    };
62→
63→    candidates.push(newCandidate);
64→
65→    return c.json<ApiResponse<Candidate>>(
66→      {
67→        success: true,
68→        data: newCandidate,
69→      },
70→      201
71→    );
72→  } catch (error) {
73→    return c.json<ApiResponse>(
74→      {
75→        success: false,
76→        error: "Invalid request body",
77→      },
78→      400
79→    );
80→  }
81→});
