  1→import {
  2→  createContext,
  3→  useCallback,
  4→  useContext,
  5→  useState,
  6→  type ReactNode,
  7→} from "react";
  8→import { mockConversations, type Conversation, type Message } from "@/data/mockConversations";
  9→
 10→interface ChatContextValue {
 11→  conversations: Conversation[];
 12→  activeConversationId: string | null;
 13→  activeConversation: Conversation | null;
 14→  openConversation: (id: string) => void;
 15→  openConversationByCandidate: (candidateId: string) => void;
 16→  closeConversation: () => void;
 17→  sendMessage: (text: string) => void;
 18→  startConversation: (candidateId: string, candidateName: string) => void;
 19→}
 20→
 21→const ChatContext = createContext<ChatContextValue | null>(null);
 22→
 23→export function ChatProvider({ children }: { children: ReactNode }) {
 24→  const [conversations, setConversations] = useState<Conversation[]>(mockConversations);
 25→  const [activeConversationId, setActiveConversationId] = useState<string | null>(null);
 26→
 27→  const activeConversation =
 28→    conversations.find((c) => c.id === activeConversationId) ?? null;
 29→
 30→  const openConversation = useCallback((id: string) => {
 31→    setActiveConversationId(id);
 32→    setConversations((prev) =>
 33→      prev.map((c) => (c.id === id ? { ...c, unread: 0 } : c)),
 34→    );
 35→  }, []);
 36→
 37→  const openConversationByCandidate = useCallback(
 38→    (candidateId: string) => {
 39→      const conv = conversations.find((c) => c.candidateId === candidateId);
 40→      if (conv) {
 41→        openConversation(conv.id);
 42→      }
 43→    },
 44→    [conversations, openConversation],
 45→  );
 46→
 47→  const closeConversation = useCallback(() => {
 48→    setActiveConversationId(null);
 49→  }, []);
 50→
 51→  const sendMessage = useCallback(
 52→    (text: string) => {
 53→      if (!activeConversationId) return;
 54→      const msg: Message = {
 55→        id: `m-${Date.now()}`,
 56→        senderId: "recruiter",
 57→        text,
 58→        timestamp: new Date(),
 59→      };
 60→      setConversations((prev) =>
 61→        prev.map((c) =>
 62→          c.id === activeConversationId
 63→            ? { ...c, messages: [...c.messages, msg] }
 64→            : c,
 65→        ),
 66→      );
 67→    },
 68→    [activeConversationId],
 69→  );
 70→
 71→  const startConversation = useCallback(
 72→    (candidateId: string, candidateName: string) => {
 73→      const existing = conversations.find((c) => c.candidateId === candidateId);
 74→      if (existing) {
 75→        openConversation(existing.id);
 76→        return;
 77→      }
 78→      const newConv: Conversation = {
 79→        id: `c-${Date.now()}`,
 80→        candidateId,
 81→        candidateName,
 82→        candidateInitial: candidateName.charAt(0),
 83→        messages: [],
 84→        unread: 0,
 85→      };
 86→      setConversations((prev) => [newConv, ...prev]);
 87→      setActiveConversationId(newConv.id);
 88→    },
 89→    [conversations, openConversation],
 90→  );
 91→
 92→  return (
 93→    <ChatContext.Provider
 94→      value={{
 95→        conversations,
 96→        activeConversationId,
 97→        activeConversation,
 98→        openConversation,
 99→        openConversationByCandidate,
100→        closeConversation,
101→        sendMessage,
102→        startConversation,
103→      }}
104→    >
105→      {children}
106→    </ChatContext.Provider>
107→  );
108→}
109→
110→export function useChat() {
111→  const ctx = useContext(ChatContext);
112→  if (!ctx) throw new Error("useChat must be used within ChatProvider");
113→  return ctx;
114→}
