 1→import { useState, type KeyboardEvent } from "react";
 2→import { motion } from "motion/react";
 3→import { useSound } from "@/hooks/useSound";
 4→import styles from "./ChatInput.module.scss";
 5→
 6→interface ChatInputProps {
 7→  onSend: (text: string) => void;
 8→}
 9→
10→export function ChatInput({ onSend }: ChatInputProps) {
11→  const [value, setValue] = useState("");
12→  const { playSound } = useSound();
13→
14→  const handleSend = () => {
15→    const trimmed = value.trim();
16→    if (!trimmed) return;
17→    playSound("click");
18→    onSend(trimmed);
19→    setValue("");
20→  };
21→
22→  const handleKeyDown = (e: KeyboardEvent) => {
23→    if (e.key === "Enter" && !e.shiftKey) {
24→      e.preventDefault();
25→      handleSend();
26→    }
27→  };
28→
29→  return (
30→    <div className={styles.inputWrapper}>
31→      <input
32→        className={styles.input}
33→        value={value}
34→        onChange={(e) => setValue(e.target.value)}
35→        onKeyDown={handleKeyDown}
36→        placeholder="Type a message..."
37→      />
38→      <motion.button
39→        className={styles.sendButton}
40→        onClick={handleSend}
41→        disabled={!value.trim()}
42→        whileTap={{ scale: 0.9 }}
43→        transition={{ type: "spring", stiffness: 400, damping: 25 }}
44→      >
45→        <svg
46→          width="16"
47→          height="16"
