 9→function timeAgo(date: Date): string {
10→  const seconds = Math.floor((Date.now() - date.getTime()) / 1000);
11→  if (seconds < 60) return "now";
12→  const minutes = Math.floor(seconds / 60);
13→  if (minutes < 60) return `${minutes}m`;
14→  const hours = Math.floor(minutes / 60);
15→  if (hours < 24) return `${hours}h`;
16→  return `${Math.floor(hours / 24)}d`;
17→}
