 1→import { useState, useEffect, useCallback } from "react";
 2→import { apiFetch } from "@/lib/api";
 3→
 4→export function useApi<T>(path: string) {
 5→  const [data, setData] = useState<T | null>(null);
 6→  const [loading, setLoading] = useState(true);
 7→  const [error, setError] = useState<string | null>(null);
 8→
 9→  const fetchData = useCallback(async () => {
10→    setLoading(true);
11→    setError(null);
12→    try {
13→      const result = await apiFetch<{ success: boolean; data: T }>(path);
14→      setData(result.data);
15→    } catch (e) {
16→      setError(e instanceof Error ? e.message : "Unknown error");
17→    } finally {
18→      setLoading(false);
19→    }
20→  }, [path]);
21→
22→  useEffect(() => {
23→    fetchData();
24→  }, [fetchData]);
25→
26→  return { data, loading, error, refetch: fetchData };
27→}
