 1→import { Hono } from "hono";
 2→import type { ApiResponse, SearchQuery, SearchResult } from "@rearden/types";
 3→import { mockCandidates } from "../data/mockCandidates.js";
 4→import { searchCandidates } from "../lib/searchEngine.js";
 5→
 6→export const searchRoutes = new Hono();
 7→
 8→// POST /api/search - Search candidates
 9→searchRoutes.post("/", async (c) => {
10→  try {
11→    const body = (await c.req.json()) as SearchQuery;
12→    const { query, filters } = body;
13→
14→    // Track search time
15→    const startTime = Date.now();
16→
17→    // Artificial delay to simulate processing
18→    await new Promise((resolve) => setTimeout(resolve, 500));
19→
20→    // Perform search
21→    const scoredCandidates = searchCandidates(mockCandidates, query, filters);
22→
23→    const endTime = Date.now();
24→    const searchTimeMs = endTime - startTime;
25→
26→    // Build response
27→    const results: (SearchResult & { candidate: typeof scoredCandidates[0]["candidate"] })[] =
28→      scoredCandidates.map((sc) => ({
29→        candidateId: sc.candidate.id,
30→        score: sc.score,
31→        matchReason: sc.matchReason,
32→        candidate: sc.candidate,
33→      }));
34→
35→    return c.json<ApiResponse>({
36→      success: true,
37→      data: {
38→        results,
39→        query,
40→        totalCandidates: mockCandidates.length,
41→        searchTimeMs,
42→      },
43→    });
44→  } catch (error) {
45→    return c.json<ApiResponse>(
46→      {
47→        success: false,
48→        error: "Invalid search request",
49→      },
50→      400
51→    );
52→  }
53→});
