 15→// POST /api/upload - Upload file
 16→uploadRoutes.post("/", async (c) => {
 17→  try {
 18→    const body = await c.req.parseBody();
 19→    const file = body.file;
 20→
 21→    if (!file || !(file instanceof File)) {
 22→      return c.json<ApiResponse>(
 23→        {
 24→          success: false,
 25→          error: "No file provided",
 26→        },
 27→        400
 28→      );
 29→    }
 30→
 31→    // Generate unique filename
 32→    const timestamp = Date.now();
 33→    const ext = extname(file.name);
 34→    const filename = `${timestamp}-${crypto.randomUUID()}${ext}`;
 35→    const filepath = join(UPLOAD_DIR, filename);
 36→
 37→    // Read file data and write to disk
 38→    const arrayBuffer = await file.arrayBuffer();
 39→    const buffer = Buffer.from(arrayBuffer);
 40→    writeFileSync(filepath, buffer);
 41→
 42→    return c.json<ApiResponse>({
 43→      success: true,
 44→      data: {
 45→        url: `/api/upload/${filename}`,
 46→        filename,
 47→      },
 48→    });
 49→  } catch (error) {
 50→    return c.json<ApiResponse>(
 51→      {
 52→        success: false,
 53→        error: "Failed to upload file",
 54→      },
 55→      500
 56→    );
 57→  }
 58→});
 59→
 60→// GET /api/upload/:filename - Serve uploaded file
 61→uploadRoutes.get("/:filename", (c) => {
 62→  const filename = c.req.param("filename");
 63→  const filepath = join(UPLOAD_DIR, filename);
 64→
 65→  if (!existsSync(filepath)) {
 66→    return c.json<ApiResponse>(
 67→      {
 68→        success: false,
 69→        error: "File not found",
 70→      },
 71→      404
 72→    );
 73→  }
 74→
 75→  try {
 76→    const fileBuffer = readFileSync(filepath);
 77→    const ext = extname(filename).toLowerCase();
 78→
 79→    // Set appropriate content type
 80→    const contentTypeMap: Record<string, string> = {
 81→      ".pdf": "application/pdf",
 82→      ".jpg": "image/jpeg",
 83→      ".jpeg": "image/jpeg",
 84→      ".png": "image/png",
 85→      ".gif": "image/gif",
 86→      ".webp": "image/webp",
 87→      ".mp4": "video/mp4",
 88→      ".webm": "video/webm",
 89→      ".doc": "application/msword",
 90→      ".docx": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
 91→      ".txt": "text/plain",
 92→    };
 93→
 94→    const contentType = contentTypeMap[ext] || "application/octet-stream";
 95→
 96→    return c.body(fileBuffer, 200, {
 97→      "Content-Type": contentType,
 98→      "Content-Disposition": `inline; filename="${filename}"`,
 99→    });
100→  } catch (error) {
101→    return c.json<ApiResponse>(
102→      {
103→        success: false,
104→        error: "Failed to read file",
105→      },
106→      500
107→    );
108→  }
109→});
